import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    def parse_element(element):
        # If the element has children, recursively parse them into a dictionary.
        if list(element):
            result = {}
            for child in element:
                child_result = parse_element(child)
                if child.tag in result:
                    # If the tag already exists, convert to list if not already
                    if not isinstance(result[child.tag], list):
                        result[child.tag] = [result[child.tag]]
                    result[child.tag].append(child_result)
                else:
                    result[child.tag] = child_result
            # Also include element attributes if present.
            if element.attrib:
                result.update(element.attrib)
            return result
        else:
            # If there are no children, return text or attributes if present.
            if element.attrib:
                data = element.attrib.copy()
                data['value'] = element.text.strip() if element.text and element.text.strip() else ''
                return data
            else:
                return element.text.strip() if element.text and element.text.strip() else ''
    
    tree = ET.parse(file_path)
    root = tree.getroot()
    return {root.tag: parse_element(root)} 

